class ChannelSelection(BaseModel):
    channel: str

channels = get_channels()

candidate_channels = [
    channel
    for channel in channels
    if channel.startswith("External") or channel.startswith("#External")
]

if len(candidate_channels) == 0:
    candidate_channels = [
        channel
        for channel in channels
        if channel.lower().startswith("external") or channel.lower().startswith("#external")
    ]

if len(candidate_channels) == 0:
    raise ValueError("No channel starts with External")

if len(candidate_channels) == 1:
    target_channel = candidate_channels[0]
else:
    selection = query_ai_assistant(
        "A user asked me to send the message 'Hi, i am a bot' to the Slack channel described as "
        "'the channel starting with External'. "
        "Here is the full list of Slack channels: {0}. "
        "Here are the candidate channels: {1}. "
        "Choose the single best matching channel from the candidate list and return its name exactly as written. "
        "If there is not exactly one clear match, raise NotEnoughInformationError.".format(
            str(channels),
            str(candidate_channels),
        ),
        ChannelSelection,
    )
    target_channel = selection.channel

send_channel_message(target_channel, "Hi, i am a bot")
print("Sent message to {0}".format(target_channel))
